class Solution {
public:
    string greatestLetter(string s) {
        int count[26] = {0};
        for (char c : s) {
            if (isupper(c)) {
                count[c - 'A'] |= 1;
            } else {
                count[c - 'a'] |= 2;
            }
        }
        for (int i = 25; i >= 0; --i) {
            if (count[i] == 3) {
                return string(1, 'A' + i);
            }
        }
        return "";
    }
};
```
